import type { DayWeather } from "../../types/weather";

export function makeDay(overrides: Partial<DayWeather> = {}): DayWeather {
  return {
    id: "today",
    date: "2026-07-08",
    is_today: true,
    is_past: false,
    temperature: 18.5,
    high_temp: 20,
    low_temp: 12,
    weather_code: 0,
    weather_descriptions: ["Clear Sky"],
    precip_chance: 15,
    ...overrides,
  };
}

export function makeWeek(): DayWeather[] {
  return [
    makeDay({
      id: "d-3",
      date: "2026-07-05",
      is_today: false,
      is_past: true,
      temperature: undefined,
      high_temp: 17,
      low_temp: 9,
      weather_code: 3,
      weather_descriptions: ["Overcast"],
      precip_chance: 5,
    }),
    makeDay({
      id: "d-2",
      date: "2026-07-06",
      is_today: false,
      is_past: true,
      temperature: undefined,
      high_temp: 16,
      low_temp: 10,
      weather_code: 61,
      weather_descriptions: ["Slight Rain"],
      precip_chance: 70,
    }),
    makeDay({
      id: "d-1",
      date: "2026-07-07",
      is_today: false,
      is_past: true,
      temperature: undefined,
      high_temp: 15,
      low_temp: 11,
      weather_code: 2,
      weather_descriptions: ["Partly Cloudy"],
      precip_chance: 20,
    }),
    makeDay(),
    makeDay({
      id: "d+1",
      date: "2026-07-09",
      is_today: false,
      is_past: false,
      temperature: undefined,
      high_temp: 19,
      low_temp: 13,
      weather_code: 95,
      weather_descriptions: ["Thunderstorm"],
      precip_chance: 80,
    }),
    makeDay({
      id: "d+2",
      date: "2026-07-10",
      is_today: false,
      is_past: false,
      temperature: undefined,
      high_temp: 21,
      low_temp: 14,
      weather_code: 1,
      weather_descriptions: ["Mainly Clear"],
      precip_chance: 0,
    }),
    makeDay({
      id: "d+3",
      date: "2026-07-11",
      is_today: false,
      is_past: false,
      temperature: undefined,
      high_temp: 22,
      low_temp: 15,
      weather_code: 45,
      weather_descriptions: ["Foggy"],
      precip_chance: 10,
    }),
  ];
}
